import{_ as l,p as i,q as e,a1 as t}from"./framework-5866ffd3.js";const a={},o=t('<blockquote><p>五大基本句型</p></blockquote><h1 id="句子的基本构成要素" tabindex="-1"><a class="header-anchor" href="#句子的基本构成要素" aria-hidden="true">#</a> 句子的基本构成要素</h1><ul><li>单词 Vocabulary <ul><li>/vəˈkæb.jə.lər.i/ US /voʊˈkæb.jə.ler.i/</li></ul></li><li>短语 Phrase /freɪz/ <ul><li>视引导的单词决定为何种短语</li></ul></li><li>句子 sentence /ˈsen.təns/ <ul><li>可独立存在的结构（有主语和动词）</li></ul></li><li>从句 clause <ul><li>UK /klɔːz/ US /klɑːz/</li><li>不可独立存在，视引导的连词确定为何种从句</li></ul></li></ul><h1 id="五大基本句型" tabindex="-1"><a class="header-anchor" href="#五大基本句型" aria-hidden="true">#</a> 五大基本句型</h1><ol><li>主语（S) + 不及物动词（Vi）</li></ol><ul><li>Dusk deepens.</li></ul><ol start="2"><li>主语(S) + 不及物动词(Vi) + 主语补语（SC)</li></ol><ul><li>I am a student.</li></ul><ol start="3"><li>主语(S) + 及物动词(Vt) + 宾语(O)</li></ol><ul><li>I love you.</li></ul><ol start="4"><li>主语(S) + 及物动词（Vt) + 间接宾语(IO) + 直接宾语(DO)</li></ol><ul><li>I give you money.</li></ul><ol start="5"><li>主语(S) + 及物动词(vt) + 宾语(O) + 宾语补语(OC)</li></ol><h1 id="八大词类" tabindex="-1"><a class="header-anchor" href="#八大词类" aria-hidden="true">#</a> 八大词类</h1><ul><li>名词 Noun /naʊn/</li><li>动词 Verb /vɝːb/</li><li>副词 Adverb /ˈæd.vɝːb/</li><li>形容词 Adjective /ˈædʒ.ek.tɪv/</li><li>代词 Pronoun /ˈproʊ.naʊn/ 代名词</li><li>介词 Preposition /ˌprep.əˈzɪʃ.ən/</li><li>连词 Conjunction /kənˈdʒʌŋk.ʃən/ <ul><li>a word such as &#39;and&#39;, &#39;but&#39;, &#39;while&#39;, or &#39;although&#39; that connects words, phrases, and clauses in a sentence</li></ul></li><li>冠词 Article /ˈɑːr.t̬ɪ.kəl/ <ul><li>&quot;a&quot;, &quot;an&quot;, and &quot;the&quot;</li></ul></li></ul>',15),n=[o];function u(r,s){return i(),e("div",null,n)}const d=l(a,[["render",u],["__file","basic_sentence.html.vue"]]);export{d as default};
